mapper.insert:
INSERT INTO RSID_VHCL (
      RSID_VHCL_NO
    , VHCL_NM
    , VHCL_NO
    , USER_NO
    , HO_NO
    , VHCL_STTS_CD
    , REG_DT
    , VHCL_FILE_NO
)VALUES (
      SEQ_RSID_VHCL.NEXTVAL
    , #{vhclNm}
    , #{vhclNo}
    , #{userNo}
    , #{hoNo}
    , #{vhclSttsCd}
    , SYSDATE
    , #{vhclFileNo}
)

mapper.delete:
DELETE FROM rsid_vhcl
WHERE   RSID_VHCL_NO = #{rsidVhclNo}
AND     USER_NO = #{userNo}

mapper.select:
SELECT  COUNT(1)
FROM    RSID_VHCL
WHERE   VHCL_NO = #{vhclNo}

SELECT  COUNT(1)
FROM    rsid_vhcl
WHERE   ho_no = #{hoNo}

SELECT FREE_PKG_CNT
FROM APT_COMPLEX
WHERE APT_CMPLEX_NO = #{aptCmplexNo}
